import React, { useState } from 'react';
import { ChevronLeft, Banknote } from 'lucide-react';

export default function DepositScreen({ onBack, onConfirm, mainBalance = 1500.00 }) {
  const [amount, setAmount] = useState('');
  const [sourceAccount, setSourceAccount] = useState('Access Bank - **** 1234');

  return (
    <div className="flex flex-col bg-white animate-in slide-in-from-right duration-300">

      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-4 sticky top-0 bg-white z-10">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-bold text-gray-900">Deposit Funds</h1>
      </div>

      {/* Main Content */}
      <div className="p-6 flex-1">
        {/* Main Balance */}
        <div className="bg-emerald-50 p-6 rounded-[2.5rem] mb-8 text-center border border-emerald-100">
          <p className="text-emerald-700 text-sm font-bold uppercase tracking-widest mb-1">Main Balance</p>
          <h2 className="text-3xl font-black text-emerald-900">${mainBalance.toLocaleString()}</h2>
        </div>

        {/* Deposit Inputs */}
        <div className="space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-700 ml-1">Amount to Deposit</label>
            <div className="relative">
              <Banknote className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
              <input 
                type="number" 
                placeholder="0.00" 
                value={amount}
                onChange={e => setAmount(e.target.value)}
                className="w-full p-4 pl-12 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] text-lg font-bold" 
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-700 ml-1">Source Account</label>
            <select 
              value={sourceAccount}
              onChange={e => setSourceAccount(e.target.value)}
              className="w-full p-4 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] appearance-none font-medium"
            >
              <option>Access Bank - **** 1234</option>
              <option>GTBank - **** 5678</option>
              <option>Add New Bank Card</option>
            </select>
          </div>
        </div>
      </div>

      {/* Confirm Button */}
      <div className="pb-64 items-centerflex">
        <button 
          onClick={() => onConfirm({ amount: parseFloat(amount), sourceAccount })}
          className="w-[90%] py-4 rounded-2xl font-bold text-white bg-[#00875A] shadow-lg shadow-emerald-100 active:scale-[0.98] transition-all"
        >
          Confirm Deposit
        </button>
      </div>
    </div>
  );
}
